UPDATE M_PERMISSION
SET
    STATUS = #{status},
    UPDATED_AT = #{updatedAt}
WHERE ID = #{id}
  AND DELETED_AT IS NULL

UPDATE M_PERMISSION
SET
    DELETED_AT = #{deletedAt},
    UPDATED_AT = #{updatedAt}
WHERE ID = #{id}
  AND DELETED_AT IS NULL

